      "label": "Polyak momentum",
      "title": "Some Methods of Speeding up the Convergence of Iteration Methods",
      "authors": [
        "B.T. Polyak"
      ],
      "authorShort": "Polyak",
      "year": 1964,
      "source": "USSR Computational Mathematics and Mathematical Physics",
      "type": "Journal Paper",
      "superCategory": "Decision-making",
