      "id": "1970_jacobson_differential_dynamic_programming",
      "label": "DDP",
      "title": "Differential Dynamic Programming",
      "authors": [
        "David H. Jacobson",
        "David Q. Mayne"
      ],
      "authorShort": "Jacobson, Mayne",
