      "label": "Quad Trees",
      "title": "Quad Trees: A Data Structure for Retrieval on Composite Keys",
      "authors": [
        "R. A. Finkel",
        "J. L. Bentley"
      ],
      "authorShort": "Finkel, Bentley",
      "year": 1974,
      "source": "Acta Informatica",
      "type": "Journal Paper",
      "superCategory": "Foundations",
