      "id": "1998_watts_collective_dynamics_of_small",
      "label": "Watts-Strogatz Model",
      "title": "Collective Dynamics of Small-World Networks",
      "authors": [
        "Duncan J. Watts",
        "Steven H. Strogatz"
      ],
      "authorShort": "Watts, Strogatz",
      "year": 1998,
      "source": "Nature",
      "type": "Journal Paper",
      "superCategory": "Foundations",
