      "id": "2000_treiber_congested_traffic_states_in",
      "label": "IDM",
      "title": "Congested Traffic States in Empirical Observations and Microscopic Simulations",
      "authors": [
        "Martin Treiber",
        "Ansgar Hennecke",
        "Dirk Helbing"
      ],
      "authorShort": "Treiber, Hennecke, Helbing",
      "year": 2000,
      "source": "Physical Review E",
