      "title": "Image Quality Assessment: From Error Visibility to Structural Similarity",
      "authors": [
        "Zhou Wang",
        "A.C. Bovik",
        "H.R. Sheikh",
        "E.P. Simoncelli"
      ],
      "authorShort": "Wang, Bovik, Sheikh",
