      "label": "A note on persistency of excitation",
      "title": "A Note on Persistency of Excitation",
      "authors": [
        "Jan C. Willems",
        "Paolo Rapisarda",
        "Ivan Markovsky",
        "Bart L.M. De Moor"
      ],
      "authorShort": "Willems, Rapisarda, Markovsky",
      "year": 2005,
      "source": "Systems and Control Letters",
