      "label": "Louvain Algorithm",
      "title": "Fast Unfolding of Communities in Large Networks",
      "authors": [
        "Vincent D. Blondel",
        "Jean-Loup Guillaume",
        "Renaud Lambiotte",
        "Etienne Lefebvre"
      ],
