      "id": "2011_brach_the_tire_force_ellipse",
      "label": "The Tire-Force Ellipse",
      "title": "The Tire-Force Ellipse (Friction Ellipse) and Tire Characteristics",
      "authors": [
        "Raymond Brach",
        "Matthew Brach"
      ],
      "authorShort": "Brach, Brach",
      "year": 2011,
      "source": "SAE Technical Paper Series",
      "type": "Conference Paper",
