      "id": "2011_van_den_berg_reciprocal_n_body_collision",
      "label": "ORCA",
      "title": "Reciprocal n-Body Collision Avoidance",
      "authors": [
        "Jur van den Berg",
        "Stephen J. Guy",
        "Ming Lin",
        "Dinesh Manocha"
      ],
      "authorShort": "Berg, Guy, Lin",
      "year": 2011,
      "source": "Springer Tracts in Advanced Robotics",
      "type": "Conference Paper",
      "superCategory": "Decision-making",
