      "title": "Deep Reinforcement Learning with Double Q-learning",
      "authors": [
        "Hado van Hasselt",
        "Arthur Guez",
        "David Silver"
      ],
      "authorShort": "Hasselt, Guez, Silver",
      "year": 2015,
