      "id": "2016_choudhury_regionally_accelerated_batch_informed",
      "label": "RABIT*",
      "title": "Regionally Accelerated Batch Informed Trees (RABIT*): A Framework to Integrate Local Information into Optimal Path Planning",
      "authors": [
        "Sanjiban Choudhury",
        "Jonathan D. Gammell",
        "Timothy D. Barfoot",
        "Siddhartha S. Srinivasa",
        "Sebastian Scherer"
      ],
      "authorShort": "Choudhury, Gammell, Barfoot",
      "year": 2016,
      "source": "IEEE International Conference on Robotics and Automation (ICRA)",
