      "label": "PI2-DDP",
      "title": "Path Integral Policy Improvement with Differential Dynamic Programming",
      "authors": [
        "Tom Lefebvre",
        "Guillaume Crevecoeur"
      ],
      "authorShort": "Lefebvre, Crevecoeur",
      "year": 2019,
      "source": "IEEE/ASME International Conference on Advanced Intelligent Mechatronics (AIM)",
      "type": "Conference Paper",
      "superCategory": "Decision-making",
