      "authors": [
        "Emilio T. Maddalena",
        "Paul Scharnhorst",
        "Yuning Jiang",
        "Colin N. Jones"
      ],
      "authorShort": "Maddalena, Scharnhorst, Jiang",
      "year": 2020,
      "source": "",
