      "id": "2003_00153",
      "label": "Learning near Optimal Policies with Low Inherent Bellman Error",
      "title": "Learning near Optimal Policies with Low Inherent Bellman Error",
      "authors": [
        "Andrea Zanette",
        "Alessandro Lazaric",
        "Mykel Kochenderfer",
        "Emma Brunskill"
      ],
      "authorShort": "Zanette, Lazaric, Kochenderfer",
      "year": 2020,
      "source": "",
