      "id": "2001_03093",
      "label": "Trajectron++",
      "title": "Trajectron++: Dynamically-Feasible Trajectory Forecasting with Heterogeneous Data",
      "authors": [
        "Tim Salzmann",
        "Boris Ivanovic",
        "Punarjay Chakravarty",
        "Marco Pavone"
      ],
      "authorShort": "Salzmann, Ivanovic, Chakravarty",
      "year": 2020,
      "source": "European Conference on Computer Vision (ECCV)",
      "type": "Conference Paper",
      "superCategory": "Prediction & Perception",
