      "authors": [
        "Viktor Makoviychuk",
        "Lukasz Wawrzyniak",
        "Yunrong Guo",
        "Michelle Lu",
        "Kier Storey",
        "Miles Macklin",
        "David Hoeller",
        "Nikita Rudin",
        "Arthur Allshire",
        "Ankur Handa",
        "Gavriel State"
      ],
      "authorShort": "Makoviychuk, Wawrzyniak, Guo",
