      "id": "2510_00272",
      "label": "BC-MPPI",
      "title": "BC-MPPI: A Probabilistic Constraint Layer for Safe Model-Predictive Path-Integral Control",
      "authors": [
        "Odichimnma Ezeji",
        "Michael Ziegltrum",
        "Giulio Turrisi",
        "Tommaso Belvedere",
        "Valerio Modugno"
      ],
