      "id": "2510_14643",
      "label": "Generative Models From and For Sampling-Based MPC: A Bootstrapped Approach For Adaptive Contact-Rich Manipulation",
      "title": "Generative Models from and for Sampling-Based MPC: A Bootstrapped Approach for Adaptive Contact-Rich Manipulation",
      "authors": [
        "Lara Brudermüller",
        "Brandon Hung",
        "Xinghao Zhu",
        "Jiuguang Wang",
        "Nick Hawes",
        "Preston Culbertson",
        "Simon Le Cleac'h"
      ],
