      "authorShort": "Wang, Luo, Bai",
      "year": 2025,
      "source": "NVIDIA",
      "type": "Technical Report",
      "superCategory": "Prediction & Perception",
      "category": "Machine Learning",
      "subCategory": "Multimodal & Embodied Models",
