      "id": "2602_00992",
      "label": "Geometry-Aware Sampling-Based Motion Planning on Riemannian Manifolds",
      "title": "Geometry-Aware Sampling-Based Motion Planning on Riemannian Manifolds",
      "authors": [
        "Phone Thiha Kyaw",
        "Jonathan Kelly"
      ],
      "authorShort": "Kyaw, Kelly",
      "year": 2026,
      "source": "",
      "type": "",
